from kafka import KafkaConsumer
import json
import ast

# Define a function to deserialize the messages from kafka topics.
def deserialization(data):
    data = bytes.decode(data)
    data_dict = json.loads(data) # Deserialize message values into dictionary object
    return data_dict

class MessageHandler:

    def __init__(self, topic):
        self.consumer = KafkaConsumer(topic, bootstrap_servers='localhost:9092') 
    
    def handle_message(self, raw_msg):
        msg = deserialization(raw_msg) # Deserialize the message.
        # Execute business logic based on message content. (Add your own business rules here.)
        if 'transactionType' in msg and msg['transactionType'] == "deposit":
            print("Processing a deposit transaction")
        
        elif 'transactionType' in msg and msg['transactionType'] == "withdrawal":
            print("Processing a withdrawal transaction")
        
        else:
            print(f"Unknown transaction type {msg}")
    
    def consume_messages(self):
        for message in self.consumer:
            self.handle_message(message.value) # Process each incoming messages by calling the 'handle_message' method.
            
# Create an instance of MessageHandler for a specific kafka topic. You can define multiple handlers if you want to consume from different topics in parallel.  
handler = MessageHandler('transaction-events') 

# Start consuming messages. It runs indefinitely until the script is stopped or kafka server connection breaks.
handler.consume_messages()